"use client";
import { memo } from 'react';
import { motion } from 'framer-motion';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';

export interface PieSlice {
  name: string;
  value: number;
}

interface EventsStatusPieProps {
  data: PieSlice[];
}

const COLORS = ['#16A34A', '#F59E0B', '#DC2626'];

function EventsStatusPieBase({ data }: EventsStatusPieProps) {
  return (
    <motion.div initial={{ opacity: 0, y: 14 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.35 }} className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} label>
            {data.map((_, i) => (
              <Cell key={`cell-${i}`} fill={COLORS[i % COLORS.length]} />
            ))}
          </Pie>
          <Tooltip contentStyle={{ borderRadius: 12, borderColor: '#E9D5FF' }} />
          <Legend />
        </PieChart>
      </ResponsiveContainer>
    </motion.div>
  );
}

export default memo(EventsStatusPieBase);
